parameters.jsCode:
const rawBody  = $('📥 Webhook').first().json;
const req      = rawBody.body || rawBody;

const employees = ($('👤 Read Employees').all() || []).map(i => i.json);
const shifts    = ($('📅 Read Shifts').all()    || []).map(i => i.json);
const rooms     = ($('🏠 Read Rooms').all()     || []).map(i => i.json);

function toISO(s) {
  if (!s) return null;
  const p = String(s).split('-');
  if (p.length !== 3) return null;
  const [a, b, c] = p;
  return a.length === 4
    ? `${a}-${b.padStart(2,'0')}-${c.padStart(2,'0')}`
    : `${c.padStart(4,'0')}-${b.padStart(2,'0')}-${a.padStart(2,'0')}`;
}

function addDays(d, n) {
  if (!d) return null;
  const dt = new Date(d + 'T00:00:00');
  if (isNaN(dt)) return null;
  dt.setDate(dt.getDate() + n);
  return dt.toISOString().split('T')[0];
}

function toMinutes(t) {
  if (!t) return null;
  const clean = String(t).trim();
  const match = clean.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)?$/i);
  if (!match) return null;
  let h = parseInt(match[1], 10);
  const m = parseInt(match[2], 10);
  const period = (match[3] || '').toUpperCase();
  if (period === 'PM' && h !== 12) h += 12;
  if (period === 'AM' && h === 12) h = 0;
  return h * 60 + m;
}

function timesOverlap(s1, e1, s2, e2) {
  const a = toMinutes(s1), b = toMinutes(e1);
  const c = toMinutes(s2), d = toMinutes(e2);
  if (a === null || b === null || c === null || d === null) return false;
  return a < d && c < b;
}

const empId     = req.employee_id;
const roomId    = req.room_id    || null;
const reqDate   = toISO(req.date);
const startTime = req.start_time || null;
const endTime   = req.end_time   || null;
const shiftType = (req.shift_type || 'Morning').trim();
const notes     = req.notes      || '';

const employee = employees.find(e => e.Employee_ID === empId) || null;
if (!employee) {
  return [{ json: { valid: false, error: 'INVALID_EMPLOYEE', error_message: `Employee ID "${empId}" not found.` } }];
}

if (!reqDate) {
  return [{ json: { valid: false, error: 'INVALID_DATE', error_message: `Date "${req.date}" is invalid.` } }];
}

const today = new Date(); today.setHours(0,0,0,0);
if (new Date(reqDate + 'T00:00:00') < today) {
  return [{ json: { valid: false, error: 'PAST_DATE', error_message: 'Cannot check schedule for a past date.' } }];
}

let room = null;
if (roomId) {
  room = rooms.find(r => r.Room_ID === roomId) || null;
  if (!room) {
    return [{ json: { valid: false, error: 'INVALID_ROOM', error_message: `Room ID "${roomId}" not found.` } }];
  }
}

const conflicts = [];

// 1. Employee double-booking
if (shiftType !== 'OFF' && startTime && endTime) {
  const empSameDay = shifts.filter(s => s.Employee_ID === empId && toISO(s.Date) === reqDate && s.Shift_Type !== 'OFF');
  for (const s of empSameDay) {
    if (timesOverlap(startTime, endTime, s.Start_Time, s.End_Time)) {
      conflicts.push({ rule: 'Employee Double-Booking', severity: 'Critical', detail: `${employee.Name} is already scheduled for a ${s.Shift_Type} shift from ${s.Start_Time} to ${s.End_Time} on ${reqDate}.` });
    }
  }
}

// 2. Room double-booking
if (roomId && room && shiftType !== 'OFF' && startTime && endTime) {
  const roomSameDay = shifts.filter(s => s.Room_ID === roomId && toISO(s.Date) === reqDate && s.Shift_Type !== 'OFF');
  for (const s of roomSameDay) {
    if (timesOverlap(startTime, endTime, s.Start_Time, s.End_Time)) {
      conflicts.push({ rule: 'Room Double-Booking', severity: 'Critical', detail: `Room "${room.Room_Name}" is already booked from ${s.Start_Time} to ${s.End_Time} on ${reqDate}.` });
    }
  }
}

// 3. Consecutive rest days
if (shiftType === 'OFF') {
  const empAllShifts = shifts.filter(s => s.Employee_ID === empId);
  const isOff = (d) => !!empAllShifts.find(s => toISO(s.Date) === d && s.Shift_Type === 'OFF');
  const dayBefore = addDays(reqDate, -1);
  const dayAfter  = addDays(reqDate,  1);
  if (isOff(dayBefore)) {
    conflicts.push({ rule: 'Consecutive Rest Days', severity: 'Critical', detail: `${employee.Name} already has a rest day on ${dayBefore}. Consecutive rest days are not allowed.` });
  } else if (isOff(dayAfter)) {
    conflicts.push({ rule: 'Consecutive Rest Days', severity: 'Critical', detail: `${employee.Name} already has a rest day on ${dayAfter}. Consecutive rest days are not allowed.` });
  }
}

// Alt rooms
const altRooms = [];
if (conflicts.some(c => c.rule === 'Room Double-Booking')) {
  for (const r of rooms) {
    if (r.Room_ID === roomId) continue;
    const hasConflict = shifts.some(s => s.Room_ID === r.Room_ID && toISO(s.Date) === reqDate && s.Shift_Type !== 'OFF' && timesOverlap(startTime, endTime, s.Start_Time, s.End_Time));
    if (!hasConflict) altRooms.push({ room_id: r.Room_ID, room_name: r.Room_Name, capacity: r.Capacity || 'N/A', location: r.Location || 'N/A' });
  }
}

// Alt dates
const altDates = [];
if (conflicts.some(c => c.rule === 'Employee Double-Booking' || c.rule === 'Consecutive Rest Days')) {
  let cursor = addDays(reqDate, 1);
  let tries  = 0;
  while (altDates.length < 3 && tries < 14) {
    tries++;
    if (!cursor) break;
    const empBusy = shifts.some(s => s.Employee_ID === empId && toISO(s.Date) === cursor && s.Shift_Type !== 'OFF' && startTime && endTime && timesOverlap(startTime, endTime, s.Start_Time, s.End_Time));
    const empAllShifts = shifts.filter(s => s.Employee_ID === empId);
    const isOff = (d) => !!empAllShifts.find(s => toISO(s.Date) === d && s.Shift_Type === 'OFF');
    const consecutiveIssue = shiftType === 'OFF' && (isOff(addDays(cursor, -1)) || isOff(addDays(cursor, 1)));
    if (!empBusy && !consecutiveIssue) {
      const dt = new Date(cursor + 'T00:00:00');
      const weekday = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][dt.getDay()];
      altDates.push({ date: cursor, weekday });
    }
    cursor = addDays(cursor, 1);
  }
}

return [{ json: {
  valid:         true,
  has_conflicts: conflicts.length > 0,
  conflicts,
  employee,
  room,
  request: {
    employee_id:   empId,
    employee_name: employee.Name,
    date:          reqDate,
    shift_type:    shiftType,
    start_time:    startTime,
    end_time:      endTime,
    room_id:       roomId,
    room_name:     room ? room.Room_Name : null,
    notes
  },
  alternatives: { rooms: altRooms, dates: altDates },
  timestamp: new Date().toISOString()
}}];

parameters.text:
=You are an HR scheduling assistant. Analyze this schedule check request and respond with a JSON decision.

FULL CONTEXT:
{{ JSON.stringify($json) }}

Employee: {{ $json.employee.Name }} (ID: {{ $json.request.employee_id }})
Department: {{ $json.employee.Department }}
Position: {{ $json.employee.Position }}
Requested Date: {{ $json.request.date }}
Shift Type: {{ $json.request.shift_type }}
Time: {{ $json.request.start_time }} - {{ $json.request.end_time }}
Room: {{ $json.request.room_name || 'Not specified' }}
Has Conflicts: {{ $json.has_conflicts }}

Conflicts ({{ $json.conflicts.length }} total):
{{ $json.conflicts.length > 0 ? $json.conflicts.map(c => '- [' + c.severity + '] ' + c.rule + ': ' + c.detail).join('\n') : 'None - schedule is CLEAR' }}

Alternative rooms available:
{{ $json.alternatives.rooms.length > 0 ? $json.alternatives.rooms.map(r => '- ' + r.room_name + ' (Capacity: ' + r.capacity + ', Location: ' + r.location + ')').join('\n') : 'None' }}

Alternative dates available:
{{ $json.alternatives.dates.length > 0 ? $json.alternatives.dates.map(d => '- ' + d.date + ' (' + d.weekday + ')').join('\n') : 'None' }}

STRICT RULES:
1. conflicts array EMPTY → status MUST be "CLEAR"
2. conflicts array has items → status MUST be "CONFLICT"
3. Address {{ $json.employee.Name }} by first name only
4. NEVER reveal other employee names or IDs
5. If CONFLICT and alt room exists, mention: {{ $json.alternatives.rooms[0] ? $json.alternatives.rooms[0].room_name : 'none' }}
6. If CONFLICT and alt date exists, mention: {{ $json.alternatives.dates[0] ? $json.alternatives.dates[0].date : 'none' }}
7. Keep message warm, 2-3 sentences max
8. suggested_room: {{ $json.alternatives.rooms[0] ? $json.alternatives.rooms[0].room_id : null }}
9. suggested_date: {{ $json.alternatives.dates[0] ? $json.alternatives.dates[0].date : null }}

Respond ONLY with raw JSON (no markdown):
{"status":"CLEAR","message":"...","suggested_room":null,"suggested_date":null,"reasoning":"one sentence"}

parameters.jsCode:
const aiOutput = $input.first().json;
const validationData = $('🔍 Validate & Check').first().json;

let aiMessage = '';
let aiReasoning = '';
let suggestedRoom = null;
let suggestedDate = null;

try {
  const raw = (aiOutput.output || aiOutput.text || JSON.stringify(aiOutput))
    .replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const match = raw.match(/\{[\s\S]*"status"[\s\S]*\}/);
  const ai = JSON.parse(match ? match[0] : raw);
  aiMessage      = ai.message        || '';
  aiReasoning    = ai.reasoning      || '';
  suggestedRoom  = ai.suggested_room || null;
  suggestedDate  = ai.suggested_date || null;
} catch(e) {
  const firstName = (validationData.employee?.Name || 'there').split(' ')[0];
  const hasConflicts = validationData.has_conflicts || false;

  aiMessage   = hasConflicts
    ? `Sorry ${firstName}, there is a scheduling conflict for this request.`
    : `Great news ${firstName}! The schedule looks clear — no conflicts found.`;
  aiReasoning = 'Automated decision based on validation';
}

// ✅ Check if clear based on has_conflicts flag
const isClear = validationData.has_conflicts === false;

// Generate unique Request_ID
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}`;
const timeStr = `${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const requestId = `SC-${dateStr}-${timeStr}`;

// Deduplicate helpers
function dedupeRooms(arr) {
  const seen = new Set();
  return (arr || []).filter(r => {
    const k = r.room_id || r.Room_ID;
    if (seen.has(k)) return false; 
    seen.add(k); 
    return true;
  });
}

function dedupeDates(arr) {
  const seen = new Set();
  return (arr || []).filter(d => {
    const k = d.date || d;
    if (seen.has(k)) return false; 
    seen.add(k); 
    return true;
  });
}

return [{ json: {
  request_id:  requestId,
  is_clear:    isClear,
  employee:    validationData.employee  || {},
  room:        validationData.room      || null,
  request:     validationData.request   || {},
  timestamp:   validationData.timestamp || new Date().toISOString(),
  conflicts:   validationData.conflicts || [],
  alternatives: {
    rooms: dedupeRooms(validationData.alternatives?.rooms || []),
    dates: dedupeDates(validationData.alternatives?.dates || [])
  },
  ai_decision: {
    status:         isClear ? 'CLEAR' : 'CONFLICT',
    reasoning:      aiReasoning,
    message:        aiMessage,
    suggested_room: suggestedRoom,
    suggested_date: suggestedDate
  }
}}];
